foreach ($file in $files) {
    $outputPath = Join-Path "Stitch_Export" $file.type | Join-Path -ChildPath $file.name
    Write-Host "Downloading $($file.name) to $outputPath..."
    try {
        curl.exe -L -o $outputPath $file.url
    } catch {
        Write-Error "Failed to download $($file.name)"
    }
}
